// Two-step source-map strip for production builds:
//
//   1. Remove all .map files from dist/ so they never reach the public CDN.
//   2. Strip every JS-style and CSS-style sourceMappingURL reference from
//      built .js and .css files so the (now-deleted) maps can't be
//      auto-discovered by browsers or dev tools.
//
// Source maps are still GENERATED by `vite build` (sourcemap: 'hidden' in
// vite.config.ts) so they exist locally if a developer wants to upload them
// to Sentry for stack-trace decoding. They just don't ship to prod.
//
// Run after `vite build` and `inject-meta.mjs`. See package.json `build`.
import { readdir, readFile, stat, unlink, writeFile } from 'node:fs/promises'
import { join } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = fileURLToPath(new URL('.', import.meta.url))
const DIST = join(__dirname, '..', 'dist')

async function walk(dir, predicate) {
  const out = []
  const entries = await readdir(dir, { withFileTypes: true })
  for (const e of entries) {
    const full = join(dir, e.name)
    if (e.isDirectory()) out.push(...(await walk(full, predicate)))
    else if (predicate(e.name)) out.push(full)
  }
  return out
}

const SOURCE_MAP_COMMENT = /\n?(\/\/[#@]\s*sourceMappingURL=[^\n]*|\/\*[#@]\s*sourceMappingURL=[\s\S]*?\*\/)\s*$/m

try {
  // Step 1: delete .map files
  const maps = await walk(DIST, (n) => n.endsWith('.map'))
  let totalBytes = 0
  for (const m of maps) {
    const s = await stat(m)
    totalBytes += s.size
    await unlink(m)
  }

  // Step 2: strip references in .js and .css
  const code = await walk(DIST, (n) => n.endsWith('.js') || n.endsWith('.css'))
  let stripped = 0
  for (const f of code) {
    const txt = await readFile(f, 'utf8')
    if (SOURCE_MAP_COMMENT.test(txt)) {
      await writeFile(f, txt.replace(SOURCE_MAP_COMMENT, ''))
      stripped++
    }
  }

  console.log(
    `strip-sourcemaps: removed ${maps.length} .map files (${(totalBytes / 1024).toFixed(0)} KB), ` +
    `stripped sourceMappingURL from ${stripped} files`,
  )
} catch (e) {
  // dist/ may not exist on a typecheck-only run
  if (e?.code === 'ENOENT') {
    console.log('strip-sourcemaps: dist/ not found, skipping')
    process.exit(0)
  }
  console.error('strip-sourcemaps: error', e)
  process.exit(1)
}
